// Parse Instagram webhook (Meta Webhook format)
// sender.id is the IGSID — required for Instagram Messaging API
const body = $input.first().json.body || $input.first().json;

// Meta Webhooks for Instagram send events in this shape:
// { entry: [{ messaging: [{ sender: { id }, recipient: { id }, message: { text } }] }] }
let igsid, username, messageText, postId;

if (body.entry?.[0]?.messaging?.[0]) {
  // Standard Meta webhook format
  const msg = body.entry[0].messaging[0];
  igsid = msg.sender?.id;
  messageText = msg.message?.text || '';
  postId = msg.message?.reply_to?.story?.id || null;
  username = body.username || msg.sender?.id; // username not always available
} else {
  // ManyChat / custom webhook format fallback
  igsid = body.igsid || body.user_id;
  username = body.username;
  messageText = body.message_text || body.comment_text || '';
  postId = body.post_id || null;
}

if (!igsid) {
  throw new Error('Missing IGSID — Instagram Messaging API requires sender IGSID, not username');
}

return [{
  json: {
    event_type: body.event_type || 'message',
    igsid: igsid,
    username: username || igsid,
    message_text: messageText,
    post_id: postId,
    keywords_detected: body.keywords_detected || [],
    detected_product: body.detected_product || null
  }
}];

