// Build response with links
const aiResponseText = $input.first().json.content;
let result;

try {
  const cleaned = aiResponseText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  result = JSON.parse(cleaned);
} catch (e) {
  result = {
    dm_text: aiResponseText,
    product_linked: false,
    calendly_offered: false,
    intent_score: 50
  };
}

const event = $input.all()[0].json;
let dmText = result.dm_text;
let bookingUrl = null;

if (result.product_linked && event.detected_product) {
  dmText += `\n\n🔗 Check it out: https://yourstore.com/products/${event.detected_product}`;
}

if (result.calendly_offered || result.intent_score > 80) {
  bookingUrl = `https://calendly.com/yourname/15min`;
  dmText += `\n\n📅 Want to chat? Book here: ${bookingUrl}`;
}

return [{
  json: {
    igsid: event.igsid,
    username: event.username,
    dm_text: dmText,
    product_linked: result.product_linked,
    calendly_offered: result.calendly_offered || result.intent_score > 80,
    intent_score: result.intent_score,
    booking_url: bookingUrl,
    timestamp: new Date().toISOString()
  }
}];

